  String toString() {
    return (StringBuffer('Room(')
          ..write('id: $id, ')
          ..write('name: $name, ')
          ..write('capacity: $capacity, ')
          ..write('notes: $notes, ')
          ..write('defaultForGroupId: $defaultForGroupId, ')
          ..write('programId: $programId, ')
