          ? const Value.absent()
          : Value(parentId),
      adultRole: Value(adultRole),
      anchoredGroupId: anchoredGroupId == null && nullToAbsent
          ? const Value.absent()
          : Value(anchoredGroupId),
      programId: programId == null && nullToAbsent
          ? const Value.absent()
          : Value(programId),
      archivedAt: archivedAt == null && nullToAbsent
          ? const Value.absent()
          : Value(archivedAt),
      authUserId: authUserId == null && nullToAbsent
          ? const Value.absent()
