class MonthlyActivity extends DataClass implements Insertable<MonthlyActivity> {
  final String id;
  final String? programId;
  final String groupId;
  final String date;
  final int position;
  final String? title;
  final String? description;
  final String? objectives;
  final String? steps;
  final String? materials;
  final String? link;

  /// v57: multi-day span (Slice 3). Rows sharing a span_id belong
  /// to one logical activity that runs across N consecutive days.
  /// The head row's span_position is 0; continuation rows are 1+.
  /// Null span_id = single-day activity.
  final String? spanId;

  /// v57: position within the span. 0 = head (the cell with the
  /// full content); 1+ = continuation days (rendered as "continued"
  /// pills unless they carry per-day content).
  final int spanPosition;

  /// v58: persisted AI add-ons. JSON blob shaped as
  /// `{ "<spec_id>": [{"heading": "...", "body": "..."}, ...] }`.
  /// Spec ids match `addonSpecs[].id`. Null = no add-ons generated
  /// yet for this activity; an empty map (`{}`) means the user
  /// generated and then deleted everything.
  final String? addons;
  final DateTime createdAt;
  final DateTime updatedAt;
  final DateTime? deletedAt;
  const MonthlyActivity({
    required this.id,
    this.programId,
    required this.groupId,
    required this.date,
    required this.position,
    this.title,
    this.description,
    this.objectives,
    this.steps,
    this.materials,
    this.link,
    this.spanId,
    required this.spanPosition,
    this.addons,
    required this.createdAt,
    required this.updatedAt,
    this.deletedAt,
  });
  @override
  Map<String, Expression> toColumns(bool nullToAbsent) {
    final map = <String, Expression>{};
    map['id'] = Variable<String>(id);
    if (!nullToAbsent || programId != null) {
      map['program_id'] = Variable<String>(programId);
    }
    map['group_id'] = Variable<String>(groupId);
    map['date'] = Variable<String>(date);
    map['position'] = Variable<int>(position);
    if (!nullToAbsent || title != null) {
      map['title'] = Variable<String>(title);
    }
    if (!nullToAbsent || description != null) {
      map['description'] = Variable<String>(description);
    }
    if (!nullToAbsent || objectives != null) {
      map['objectives'] = Variable<String>(objectives);
    }
    if (!nullToAbsent || steps != null) {
      map['steps'] = Variable<String>(steps);
    }
    if (!nullToAbsent || materials != null) {
      map['materials'] = Variable<String>(materials);
    }
    if (!nullToAbsent || link != null) {
      map['link'] = Variable<String>(link);
    }
    if (!nullToAbsent || spanId != null) {
      map['span_id'] = Variable<String>(spanId);
    }
    map['span_position'] = Variable<int>(spanPosition);
    if (!nullToAbsent || addons != null) {
      map['addons'] = Variable<String>(addons);
    }
    map['created_at'] = Variable<DateTime>(createdAt);
    map['updated_at'] = Variable<DateTime>(updatedAt);
    if (!nullToAbsent || deletedAt != null) {
      map['deleted_at'] = Variable<DateTime>(deletedAt);
    }
    return map;
  }

